final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var currentUser: UserAccount
    @Published private(set) var lastHandledLink: URL?
    @Published private(set) var lastStatusMessage: String?

    private let storage = PromoStorage()

    static let dateFormatter: DateFormatter = {
        let df = DateFormatter()
        df.dateStyle = .medium
        df.timeStyle = .medium
        return df
    }()

    private init() {
        if let loaded = storage.loadUser() {
            self.currentUser = loaded
        } else {
            self.currentUser = UserAccount(id: UUID().uuidString, appliedPromoCode: nil, appliedDiscountPercent: nil, lastPromoAppliedAt: nil)
            storage.saveUser(currentUser)
        }
    }

    func handleIncomingURL(_ url: URL) -> Bool {
        lastHandledLink = url

        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            lastStatusMessage = "Invalid URL."
            return false
        }

        guard let host = components.host?.lowercased(), host == "myapp.com" else {
            lastStatusMessage = "Ignored: host mismatch."
            return false
        }

        let path = components.path.lowercased()
        guard path == "/promo" else {
            lastStatusMessage = "Ignored: path mismatch."
            return false
        }

        let queryItems = components.queryItems ?? []
        let code = queryItems.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountString = queryItems.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let promoCode = code, !promoCode.isEmpty else {
            lastStatusMessage = "Missing promo code."
            return false
        }

        guard let discountString, let discount = Int(discountString), (0...100).contains(discount) else {
            lastStatusMessage = "Invalid discount."
            return false
        }

        applyPromo(code: promoCode, discountPercent: discount)
        lastStatusMessage = "Applied promo \(promoCode) with \(discount)% discount to user \(currentUser.id)."
        return true
    }

    func applyPromo(code: String, discountPercent: Int) {
        currentUser.appliedPromoCode = code
        currentUser.appliedDiscountPercent = discountPercent
        currentUser.lastPromoAppliedAt = Date()
        storage.saveUser(currentUser)
    }

    func resetUserPromo() {
        currentUser.appliedPromoCode = nil
        currentUser.appliedDiscountPercent = nil
        currentUser.lastPromoAppliedAt = nil
        storage.saveUser(currentUser)
        lastStatusMessage = "Promo reset."
    }
}

struct UserAccount: Codable {
    var id: String
    var appliedPromoCode: String?
    var appliedDiscountPercent: Int?
    var lastPromoAppliedAt: Date?
}

final class PromoStorage {
    private let key = "PromoUniversalLinksApp.UserAccount"

    func saveUser(_ user: UserAccount) {
        do {
            let data = try JSONEncoder().encode(user)
            UserDefaults.standard.set(data, forKey: key)
        } catch {
            // ignore
        }
    }

    func loadUser() -> UserAccount? {
        guard let data = UserDefaults.standard.data(forKey: key) else { return nil }
        return try? JSONDecoder().decode(UserAccount.self, from: data)
    }
}